#include <limits.h>

int parse_int32(const char *s, int32_t *out)
{
    if (!s || !out)
        return 0;

    while (isspace((unsigned char)*s))
        s++;

    if (!*s)
        return 0;

    int sign = 1;
    if (*s == '-') {
        sign = -1;
        s++;
    } else if (*s == '+') {
        s++;
    }

    if (!*s)
        return 0;

    int32_t acc = 0;

    while (isdigit((unsigned char)*s)) {
        int digit = *s - '0';

        if (sign > 0) {
            if (acc > INT32_MAX / 10 ||
               (acc == INT32_MAX / 10 && digit > INT32_MAX % 10))
                return 0;
        } else {
            if (acc > -(INT32_MIN + 1) / 10 ||
               (acc == -(INT32_MIN + 1) / 10 &&
                digit > (-(INT32_MIN + 1)) % 10))
                return 0;
        }

        acc = acc * 10 + digit;
        s++;
    }

    while (isspace((unsigned char)*s))
        s++;

    if (*s != '\0')
        return 0;

    *out = sign * acc;
    return 1;
}

